## New file: `packages/relay/src/lib/thread-id.ts`

```typescript
/**
 * Thread ID codec interface and platform implementations.
 *
 * Standardizes encoding/decoding of platform thread IDs to/from relay subjects.
 * Replaces per-adapter buildSubject/extractChatId/extractChannelId functions
 * with a unified interface.
 *
 * @module relay/lib/thread-id
 */

/**
 * Codec for encoding/decoding platform thread IDs to/from relay subjects.
 *
 * Each platform adapter provides a codec that handles its subject format.
 * This replaces the per-adapter buildSubject/extractChatId/extractChannelId
 * functions with a unified interface.
 */
export interface ThreadIdCodec {
  /** The subject prefix this codec handles (e.g., 'relay.human.telegram'). */
  readonly prefix: string;

  /**
   * Build a relay subject from a platform thread ID.
   *
   * @param platformId - Platform-native identifier (e.g., Telegram chatId, Slack channelId)
   * @param channelType - Whether the thread is a DM or group conversation
   */
  encode(platformId: string, channelType: 'dm' | 'group'): string;

  /**
   * Extract a platform thread ID and channel type from a relay subject.
   *
   * @param subject - A relay subject under this codec's prefix
   * @returns Decoded thread info, or null if the subject doesn't match
   */
  decode(subject: string): { platformId: string; channelType: 'dm' | 'group' } | null;
}

/**
 * Thread ID codec for the Telegram adapter.
 *
 * Subject format:
 * - DM: `relay.human.telegram.{chatId}`
 * - Group: `relay.human.telegram.group.{chatId}`
 *
 * Replaces buildSubject() and extractChatId() from telegram/inbound.ts.
 */
export class TelegramThreadIdCodec implements ThreadIdCodec {
  readonly prefix = 'relay.human.telegram';

  encode(platformId: string, channelType: 'dm' | 'group'): string {
    if (channelType === 'group') {
      return `${this.prefix}.group.${platformId}`;
    }
    return `${this.prefix}.${platformId}`;
  }

  decode(subject: string): { platformId: string; channelType: 'dm' | 'group' } | null {
    if (!subject.startsWith(this.prefix)) return null;
    const remainder = subject.slice(this.prefix.length + 1);
    if (!remainder) return null;

    if (remainder.startsWith('group.')) {
      const id = remainder.slice('group.'.length);
      if (!id) return null;
      return { platformId: id, channelType: 'group' };
    }

    return { platformId: remainder, channelType: 'dm' };
  }
}

/**
 * Thread ID codec for the Slack adapter.
 *
 * Subject format:
 * - DM: `relay.human.slack.{channelId}`
 * - Group: `relay.human.slack.group.{channelId}`
 *
 * Replaces buildSubject() and extractChannelId() from slack/inbound.ts.
 */
export class SlackThreadIdCodec implements ThreadIdCodec {
  readonly prefix = 'relay.human.slack';

  encode(platformId: string, channelType: 'dm' | 'group'): string {
    if (channelType === 'group') {
      return `${this.prefix}.group.${platformId}`;
    }
    return `${this.prefix}.${platformId}`;
  }

  decode(subject: string): { platformId: string; channelType: 'dm' | 'group' } | null {
    if (!subject.startsWith(this.prefix)) return null;
    const remainder = subject.slice(this.prefix.length + 1);
    if (!remainder) return null;

    if (remainder.startsWith('group.')) {
      const id = remainder.slice('group.'.length);
      return id ? { platformId: id, channelType: 'group' } : null;
    }

    return { platformId: remainder, channelType: 'dm' };
  }
}

/**
 * Thread ID codec for Chat SDK-backed adapters.
 *
 * Subject format:
 * - DM: `relay.human.telegram-chatsdk.{chatId}`
 * - Group: `relay.human.telegram-chatsdk.group.{chatId}`
 *
 * Same structural convention as existing adapters but with the
 * `telegram-chatsdk` prefix segment.
 */
export class ChatSdkTelegramThreadIdCodec implements ThreadIdCodec {
  readonly prefix = 'relay.human.telegram-chatsdk';

  encode(platformId: string, channelType: 'dm' | 'group'): string {
    if (channelType === 'group') {
      return `${this.prefix}.group.${platformId}`;
    }
    return `${this.prefix}.${platformId}`;
  }

  decode(subject: string): { platformId: string; channelType: 'dm' | 'group' } | null {
    if (!subject.startsWith(this.prefix)) return null;
    const remainder = subject.slice(this.prefix.length + 1);
    if (!remainder) return null;

    if (remainder.startsWith('group.')) {
      const id = remainder.slice('group.'.length);
      return id ? { platformId: id, channelType: 'group' } : null;
    }

    return { platformId: remainder, channelType: 'dm' };
  }
}
```

## New file: `packages/relay/src/lib/__tests__/thread-id.test.ts`

Write comprehensive unit tests:

```typescript
import { describe, it, expect } from 'vitest';
import {
  TelegramThreadIdCodec,
  SlackThreadIdCodec,
  ChatSdkTelegramThreadIdCodec,
} from '../thread-id.js';

describe('TelegramThreadIdCodec', () => {
  const codec = new TelegramThreadIdCodec();

  it('has the correct prefix', () => {
    expect(codec.prefix).toBe('relay.human.telegram');
  });

  it('encodes a DM subject', () => {
    expect(codec.encode('12345', 'dm')).toBe('relay.human.telegram.12345');
  });

  it('encodes a group subject', () => {
    expect(codec.encode('-100123', 'group')).toBe('relay.human.telegram.group.-100123');
  });

  it('round-trips a DM encode/decode', () => {
    const subject = codec.encode('12345', 'dm');
    const decoded = codec.decode(subject);
    expect(decoded).toEqual({ platformId: '12345', channelType: 'dm' });
  });

  it('round-trips a group encode/decode', () => {
    const subject = codec.encode('-100123', 'group');
    const decoded = codec.decode(subject);
    expect(decoded).toEqual({ platformId: '-100123', channelType: 'group' });
  });

  it('returns null for a non-matching prefix', () => {
    expect(codec.decode('relay.human.slack.C123')).toBeNull();
  });

  it('returns null for prefix-only subject (no chat ID)', () => {
    expect(codec.decode('relay.human.telegram')).toBeNull();
  });

  it('returns null for group prefix with no ID', () => {
    expect(codec.decode('relay.human.telegram.group.')).toBeNull();
  });
});

describe('SlackThreadIdCodec', () => {
  const codec = new SlackThreadIdCodec();

  it('has the correct prefix', () => {
    expect(codec.prefix).toBe('relay.human.slack');
  });

  it('round-trips a DM encode/decode', () => {
    const subject = codec.encode('D0123ABC', 'dm');
    expect(subject).toBe('relay.human.slack.D0123ABC');
    const decoded = codec.decode(subject);
    expect(decoded).toEqual({ platformId: 'D0123ABC', channelType: 'dm' });
  });

  it('round-trips a group encode/decode', () => {
    const subject = codec.encode('C0456DEF', 'group');
    expect(subject).toBe('relay.human.slack.group.C0456DEF');
    const decoded = codec.decode(subject);
    expect(decoded).toEqual({ platformId: 'C0456DEF', channelType: 'group' });
  });

  it('returns null for non-matching prefix', () => {
    expect(codec.decode('relay.human.telegram.12345')).toBeNull();
  });

  it('returns null for empty group ID', () => {
    expect(codec.decode('relay.human.slack.group.')).toBeNull();
  });
});

describe('ChatSdkTelegramThreadIdCodec', () => {
  const codec = new ChatSdkTelegramThreadIdCodec();

  it('has the correct prefix', () => {
    expect(codec.prefix).toBe('relay.human.telegram-chatsdk');
  });

  it('round-trips a DM encode/decode', () => {
    const subject = codec.encode('99999', 'dm');
    expect(subject).toBe('relay.human.telegram-chatsdk.99999');
    const decoded = codec.decode(subject);
    expect(decoded).toEqual({ platformId: '99999', channelType: 'dm' });
  });

  it('round-trips a group encode/decode', () => {
    const subject = codec.encode('-200456', 'group');
    expect(subject).toBe('relay.human.telegram-chatsdk.group.-200456');
    const decoded = codec.decode(subject);
    expect(decoded).toEqual({ platformId: '-200456', channelType: 'group' });
  });

  it('does not match the grammy telegram prefix', () => {
    expect(codec.decode('relay.human.telegram.12345')).toBeNull();
  });
});
