Implement the `AsyncQueue<T>` class that provides a push-pull async iterable queue for streaming text deltas to adapters.

## New file: `packages/relay/src/lib/async-queue.ts`

```typescript
/**
 * Push-pull async iterable queue.
 *
 * Producers push values; consumers await them via `for await...of`.
 * Completes when `complete()` is called; throws when `fail()` is called.
 * Zero dependencies, ~45 lines.
 *
 * @module relay/lib/async-queue
 */
export class AsyncQueue<T> implements AsyncIterable<T> {
  private queue: T[] = [];
  private resolve: ((value: IteratorResult<T>) => void) | null = null;
  private done = false;
  private error: Error | null = null;

  /** Push a value to the queue. Ignored if already completed or failed. */
  push(value: T): void {
    if (this.done) return;
    if (this.resolve) {
      const r = this.resolve;
      this.resolve = null;
      r({ value, done: false });
    } else {
      this.queue.push(value);
    }
  }

  /** Signal that no more values will be pushed. */
  complete(): void {
    this.done = true;
    if (this.resolve) {
      const r = this.resolve;
      this.resolve = null;
      r({ value: undefined as unknown as T, done: true });
    }
  }

  /** Signal an error — the consumer's `for await` will throw. */
  fail(err: Error): void {
    this.done = true;
    this.error = err;
    if (this.resolve) {
      const r = this.resolve;
      this.resolve = null;
      // Resolve with done:true — the error is thrown on next iteration check
      r({ value: undefined as unknown as T, done: true });
    }
  }

  async *[Symbol.asyncIterator](): AsyncIterator<T> {
    while (true) {
      if (this.queue.length > 0) {
        yield this.queue.shift()!;
        continue;
      }
      if (this.error) throw this.error;
      if (this.done) return;
      // Wait for next push/complete/fail
      const result = await new Promise<IteratorResult<T>>((resolve) => {
        this.resolve = resolve;
      });
      if (result.done) {
        if (this.error) throw this.error;
        return;
      }
      yield result.value;
    }
  }
}
```

## New file: `packages/relay/src/lib/__tests__/async-queue.test.ts`

```typescript
import { describe, it, expect } from 'vitest';
import { AsyncQueue } from '../async-queue.js';

describe('AsyncQueue', () => {
  it('yields pushed values in order', async () => {
    const q = new AsyncQueue<string>();
    q.push('a');
    q.push('b');
    q.push('c');
    q.complete();

    const collected: string[] = [];
    for await (const val of q) {
      collected.push(val);
    }
    expect(collected).toEqual(['a', 'b', 'c']);
  });

  it('yields values pushed after iteration starts', async () => {
    const q = new AsyncQueue<string>();
    const collected: string[] = [];

    const consumer = (async () => {
      for await (const val of q) {
        collected.push(val);
      }
    })();

    // Push after consumer is waiting
    q.push('x');
    q.push('y');
    q.complete();

    await consumer;
    expect(collected).toEqual(['x', 'y']);
  });

  it('completes immediately when complete() called before iteration', async () => {
    const q = new AsyncQueue<string>();
    q.complete();

    const collected: string[] = [];
    for await (const val of q) {
      collected.push(val);
    }
    expect(collected).toEqual([]);
  });

  it('ignores pushes after complete()', async () => {
    const q = new AsyncQueue<string>();
    q.push('a');
    q.complete();
    q.push('b'); // should be ignored

    const collected: string[] = [];
    for await (const val of q) {
      collected.push(val);
    }
    expect(collected).toEqual(['a']);
  });

  it('throws the error from fail() during iteration', async () => {
    const q = new AsyncQueue<string>();
    q.push('a');

    const collected: string[] = [];
    const consumer = (async () => {
      for await (const val of q) {
        collected.push(val);
      }
    })();

    // Let consumer process 'a', then fail
    await new Promise((r) => setTimeout(r, 10));
    q.fail(new Error('stream error'));

    await expect(consumer).rejects.toThrow('stream error');
    expect(collected).toEqual(['a']);
  });

  it('throws immediately when fail() called before iteration starts', async () => {
    const q = new AsyncQueue<string>();
    q.fail(new Error('pre-fail'));

    const consumer = (async () => {
      const collected: string[] = [];
      for await (const val of q) {
        collected.push(val);
      }
      return collected;
    })();

    await expect(consumer).rejects.toThrow('pre-fail');
  });

  it('ignores pushes after fail()', async () => {
    const q = new AsyncQueue<string>();
    q.fail(new Error('oops'));
    q.push('ignored');

    await expect((async () => {
      for await (const _ of q) { /* noop */ }
    })()).rejects.toThrow('oops');
  });

  it('handles interleaved push and consume', async () => {
    const q = new AsyncQueue<number>();
    const collected: number[] = [];

    const consumer = (async () => {
      for await (const val of q) {
        collected.push(val);
      }
    })();

    for (let i = 0; i < 5; i++) {
      q.push(i);
      // Small delay to let consumer process
      await new Promise((r) => setTimeout(r, 1));
    }
    q.complete();

    await consumer;
    expect(collected).toEqual([0, 1, 2, 3, 4]);
  });
});
```

