## New file: `packages/relay/src/adapters/telegram/grammy-platform-client.ts`

This class wraps the grammy `Bot` instance and implements `PlatformClient`. It consolidates the following existing logic:

- `sendAndTrack()` from `outbound.ts` becomes `postMessage()`
- `sendMessageDraft`-based streaming becomes `stream()`
- Inline keyboard approval rendering becomes `postAction()`
- `sendChatAction` typing indicator logic becomes `startTyping()` / `stopTyping()`

```typescript
/**
 * Grammy-based platform client for Telegram.
 *
 * Wraps the grammy Bot instance to provide PlatformClient-compliant
 * communication methods. Owns the ResponseBuffer map, typing intervals,
 * and draft update throttling state.
 *
 * @module relay/adapters/telegram/grammy-platform-client
 */
import type { Bot } from 'grammy';
import type { PlatformClient, RelayLogger } from '../../types.js';
import { noopLogger } from '../../types.js';
import { formatForPlatform, truncateText } from '../../lib/payload-utils.js';
import { sendMessageDraft } from './stream-api.js';
import { MAX_MESSAGE_LENGTH } from './inbound.js';

/** Refresh interval for Telegram typing indicator (expires after 5s). */
const TYPING_REFRESH_MS = 4_000;

/** Minimum interval (ms) between sendMessageDraft calls for a single chat. */
const DRAFT_UPDATE_INTERVAL_MS = 200;

export class GrammyPlatformClient implements PlatformClient {
  readonly platform = 'telegram';

  private readonly typingIntervals = new Map<string, ReturnType<typeof setInterval>>();
  private readonly lastDraftUpdate = new Map<string, number>();
  private readonly logger: RelayLogger;

  constructor(
    private readonly bot: Bot,
    logger?: RelayLogger
  ) {
    this.logger = logger ?? noopLogger;
  }

  async postMessage(
    threadId: string,
    content: string,
    _format?: string
  ): Promise<{ messageId: string }> {
    const chatId = Number(threadId);
    const html = formatForPlatform(truncateText(content, MAX_MESSAGE_LENGTH), 'telegram');
    const sent = await this.bot.api.sendMessage(chatId, html, {
      parse_mode: 'HTML',
    } as Parameters<typeof this.bot.api.sendMessage>[2]);
    return { messageId: String(sent.message_id) };
  }

  async editMessage(
    threadId: string,
    messageId: string,
    content: string
  ): Promise<void> {
    const chatId = Number(threadId);
    const html = formatForPlatform(truncateText(content, MAX_MESSAGE_LENGTH), 'telegram');
    await this.bot.api.editMessageText(chatId, Number(messageId), html, {
      parse_mode: 'HTML',
    });
  }

  async deleteMessage(threadId: string, messageId: string): Promise<void> {
    const chatId = Number(threadId);
    await this.bot.api.deleteMessage(chatId, Number(messageId));
  }

  handleInbound(): void {
    // Inbound handling is managed by the TelegramAdapter directly via grammy event handlers.
    // This is a no-op for the platform client.
  }

  async stream(
    threadId: string,
    content: AsyncIterable<string>
  ): Promise<{ messageId: string }> {
    const chatId = Number(threadId);
    let accumulated = '';

    for await (const chunk of content) {
      accumulated += chunk;

      // Throttle draft updates
      if (chatId > 0) { // DMs only for sendMessageDraft
        const lastUpdate = this.lastDraftUpdate.get(threadId) ?? 0;
        if (Date.now() - lastUpdate >= DRAFT_UPDATE_INTERVAL_MS) {
          this.lastDraftUpdate.set(threadId, Date.now());
          try {
            await sendMessageDraft(this.bot, chatId, accumulated);
          } catch {
            // sendMessageDraft not available or failed — continue accumulating
          }
        }
      }
    }

    this.lastDraftUpdate.delete(threadId);

    // Send final message
    if (accumulated) {
      const html = formatForPlatform(
        truncateText(accumulated, MAX_MESSAGE_LENGTH),
        'telegram'
      );
      const sent = await this.bot.api.sendMessage(chatId, html, {
        parse_mode: 'HTML',
      } as Parameters<typeof this.bot.api.sendMessage>[2]);
      return { messageId: String(sent.message_id) };
    }

    return { messageId: '' };
  }

  startTyping(threadId: string): void {
    const chatId = Number(threadId);
    // Clear existing
    this.stopTyping(threadId);
    // Send immediately
    void this.bot.api.sendChatAction(chatId, 'typing').catch(() => {});
    // Refresh every 4s
    const intervalId = setInterval(() => {
      void this.bot.api.sendChatAction(chatId, 'typing').catch(() => {
        this.stopTyping(threadId);
      });
    }, TYPING_REFRESH_MS);
    this.typingIntervals.set(threadId, intervalId);
  }

  stopTyping(threadId: string): void {
    const existing = this.typingIntervals.get(threadId);
    if (existing !== undefined) {
      clearInterval(existing);
      this.typingIntervals.delete(threadId);
    }
  }

  async destroy(): Promise<void> {
    for (const interval of this.typingIntervals.values()) clearInterval(interval);
    this.typingIntervals.clear();
    this.lastDraftUpdate.clear();
  }
}
```

Note: The approval card rendering (`handleApprovalRequired` from `outbound.ts`) remains in the adapter's `deliver()` method for now because it requires access to the `callbackIdMap` and `pendingApprovalTimeouts` state that is tied to the adapter's callback query handler. The `postAction()` method on `PlatformClient` can be implemented later as a follow-up when the approval system is further abstracted.

