import type { WebClient } from '@slack/web-api';
import type { PlatformClient, RelayLogger } from '../../types.js';
import { noopLogger } from '../../types.js';

export class SlackPlatformClient implements PlatformClient {
  readonly platform = 'slack';
  private readonly logger: RelayLogger;

  constructor(
    private readonly client: WebClient,
    private readonly config: { nativeStreaming?: boolean },
    logger?: RelayLogger
  ) {
    this.logger = logger ?? noopLogger;
  }

  async postMessage(
    threadId: string,
    content: string,
    _format?: string
  ): Promise<{ messageId: string }> {
    const result = await this.client.chat.postMessage({
      channel: threadId,
      text: content,
      mrkdwn: true,
    });
    return { messageId: result.ts ?? '' };
  }

  async editMessage(
    threadId: string,
    messageId: string,
    content: string
  ): Promise<void> {
    await this.client.chat.update({
      channel: threadId,
      ts: messageId,
      text: content,
    });
  }

  async deleteMessage(threadId: string, messageId: string): Promise<void> {
    await this.client.chat.delete({
      channel: threadId,
      ts: messageId,
    });
  }

  handleInbound(): void {
    // Inbound handled by SlackAdapter via Bolt event handlers
  }

  async stream(
    threadId: string,
    content: AsyncIterable<string>
  ): Promise<{ messageId: string }> {
    // Implementation migrates from existing stream.ts logic:
    // - If nativeStreaming: use client.chat.startStream / appendStream / stopStream
    // - Else: use postMessage + update (legacy mode)
    let accumulated = '';
    let messageTs = '';

    for await (const chunk of content) {
      accumulated += chunk;
      if (!messageTs) {
        // First chunk: post initial message
        const result = await this.client.chat.postMessage({
          channel: threadId,
          text: accumulated,
          mrkdwn: true,
        });
        messageTs = result.ts ?? '';
      } else {
        // Subsequent chunks: update existing message
        await this.client.chat.update({
          channel: threadId,
          ts: messageTs,
          text: accumulated,
        });
      }
    }

    return { messageId: messageTs };
  }

  startTyping(threadId: string): void {
    // Add hourglass reaction — best-effort
    void this.addReaction(threadId).catch(() => {});
  }

  stopTyping(threadId: string): void {
    // Remove hourglass reaction — best-effort
    void this.removeReaction(threadId).catch(() => {});
  }

  async destroy(): Promise<void> {
    // No persistent state to clean up
  }

  private async addReaction(_threadId: string): Promise<void> {
    // Implementation migrates from existing outbound.ts hourglass logic
