/**
 * Inbound message handling for the Chat SDK Telegram adapter.
 *
 * Maps Chat SDK message events to StandardPayload format for relay publishing.
 *
 * @module relay/adapters/telegram-chatsdk/inbound
 */
import type { StandardPayload } from '@dorkos/shared/relay-schemas';
import { ChatSdkTelegramThreadIdCodec } from '../../lib/thread-id.js';

const codec = new ChatSdkTelegramThreadIdCodec();

/** Maximum message length for Telegram. */
export const MAX_MESSAGE_LENGTH = 4096;

/**
 * Build a StandardPayload from a Chat SDK message event.
 *
 * @param event - The Chat SDK message event
 * @returns Subject and payload tuple for relay publishing
 */
export function buildInboundPayload(event: {
  chat: { id: number; type: string };
  text?: string;
  from?: { firstName?: string };
  messageId?: number;
}): { subject: string; payload: StandardPayload } {
  const chatId = String(event.chat.id);
  const isGroup = event.chat.type === 'group' || event.chat.type === 'supergroup';
  const subject = codec.encode(chatId, isGroup ? 'group' : 'dm');

  const payload: StandardPayload = {
    content: event.text ?? '',
    senderName: event.from?.firstName ?? 'unknown',
    channelType: isGroup ? 'group' : 'dm',
    responseContext: {
      platform: 'telegram',
      maxLength: MAX_MESSAGE_LENGTH,
      supportedFormats: ['text', 'markdown'],
      instructions: `Reply to subject ${subject} to respond.`,
    },
    platformData: {
      chatId: event.chat.id,
      messageId: event.messageId,
    },
  };

  return { subject, payload };
}
