2. **Inbound message forwarding**: Mock a Chat SDK message event, verify it is published to the relay with the correct subject and `StandardPayload` format.

3. **Echo prevention**: Verify that `deliver()` returns success without posting when `envelope.from` starts with the adapter's subject prefix.

4. **Non-streaming delivery**: Verify `deliver()` calls `thread.post()` for standard payloads.

5. **Approval text rendering**: Verify `deliver()` renders approval events as text descriptions.

6. **deliverStream()**: Verify it calls `thread.post()` with the `AsyncIterable<string>` stream.

7. **deliverStream() error handling**: Verify errors from `thread.post()` are captured and returned as failed `DeliveryResult`.

8. **Subject decoding**: Verify that subjects under `relay.human.telegram-chatsdk` are correctly decoded to platform IDs.

Test structure:

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { ChatSdkTelegramAdapter } from '../adapter.js';
import { createMockRelayPublisher } from '../../../testing/mock-relay-publisher.js';
import { createMockRelayEnvelope } from '../../../testing/mock-relay-envelope.js';

// Mock the chat SDK modules
vi.mock('chat', () => ({
  Chat: vi.fn().mockImplementation(() => ({
    on: vi.fn(),
    start: vi.fn().mockResolvedValue(undefined),
    stop: vi.fn().mockResolvedValue(undefined),
    getThread: vi.fn().mockReturnValue({
      post: vi.fn().mockResolvedValue(undefined),
    }),
  })),
  createTelegramAdapter: vi.fn(),
  createMemoryState: vi.fn(),
}));

describe('ChatSdkTelegramAdapter', () => {
  let adapter: ChatSdkTelegramAdapter;
  let relay: ReturnType<typeof createMockRelayPublisher>;

  beforeEach(() => {
    adapter = new ChatSdkTelegramAdapter('test-chatsdk', { token: 'test:token' });
    relay = createMockRelayPublisher();
  });

  afterEach(async () => {
    await adapter.stop();
  });

  it('starts and stops without errors', async () => {
    await adapter.start(relay);
    expect(adapter.getStatus().state).toBe('connected');
    await adapter.stop();
    expect(adapter.getStatus().state).toBe('disconnected');
  });

  it('skips echo messages', async () => {
    await adapter.start(relay);
    const envelope = createMockRelayEnvelope({
      subject: 'relay.human.telegram-chatsdk.12345',
      from: 'relay.human.telegram-chatsdk.bot',
    });
    const result = await adapter.deliver('relay.human.telegram-chatsdk.12345', envelope);
    expect(result.success).toBe(true);
    // Should not have called thread.post()
  });

  it('delivers standard payload via thread.post()', async () => {
    await adapter.start(relay);
    const envelope = createMockRelayEnvelope({
      subject: 'relay.human.telegram-chatsdk.12345',
      from: 'relay.agent.test',
      payload: 'Hello from agent',
    });
    const result = await adapter.deliver('relay.human.telegram-chatsdk.12345', envelope);
    expect(result.success).toBe(true);
  });

  it('returns error when not started', async () => {
    const envelope = createMockRelayEnvelope({
      subject: 'relay.human.telegram-chatsdk.12345',
      from: 'relay.agent.test',
    });
    const result = await adapter.deliverStream!(
      'relay.human.telegram-chatsdk.12345',
      '12345',
      (async function* () { yield 'hello'; })(),
    );
    expect(result.success).toBe(false);
    expect(result.error).toContain('not started');
  });
});
